	// (the operator moves the ref themselves).
	if opts.LandingAdvancer != nil {
		land, landErr := opts.LandingAdvancer(res)
		if landErr != nil {
			return nil, fmt.Errorf("land advancer: %w", landErr)
		}
		switch land.Status {
		case "landed":
			landing.Outcome = "merged"
			if land.Merged {
				landing.Reason = "merged onto current tip"
			}
		case "preserved":
			landing.Outcome = "preserved"
			landing.PreserveRef = land.PreserveRef
			landing.Reason = land.Reason
		case "no-changes":
			landing.Outcome = "no-changes"
			landing.Reason = land.Reason
		default:
			landing.Outcome = "preserved"
			landing.Reason = "unknown land status: " + land.Status
		}
		return landing, nil
	}

	// No advancer: preserve under refs/ddx/iterations/ as a safe fallback.
	ref := PreserveRef(res.BeadID, res.BaseRev)
	if err := gitOps.UpdateRef(projectRoot, ref, res.ResultRev); err != nil {
		return nil, fmt.Errorf("preserving result ref (no land advancer): %w", err)
	}
	landing.Outcome = "preserved"
	landing.PreserveRef = ref
	landing.Reason = "no land advancer configured"
	return landing, nil
}

// ApplyLandingToResult merges a BeadLandingResult's fields into an
// ExecuteBeadResult so callers can output a single unified record. It
// overwrites Outcome, Status, Detail, Reason, PreserveRef, GateResults,
// RequiredExecSummary, and ChecksFile based on the landing decision.
func ApplyLandingToResult(res *ExecuteBeadResult, landing *BeadLandingResult) {
	res.Outcome = landing.Outcome
	res.Reason = landing.Reason
	res.PreserveRef = landing.PreserveRef
	res.GateResults = landing.GateResults
	res.RequiredExecSummary = landing.RequiredExecSummary
	res.ChecksFile = landing.ChecksFile
	res.RatchetEvidence = landing.RatchetEvidence
	res.RatchetSummary = landing.RatchetSummary
	// Re-classify status based on landing outcome and reason.
	res.Status = ClassifyExecuteBeadStatus(landing.Outcome, res.ExitCode, landing.Reason)
	res.Detail = ExecuteBeadStatusDetail(res.Status, landing.Reason, res.Error)
	// Refine failure_mode with landing-level signals. A clean merge clears
	// the field; merge conflict or gate failure overrides the worker-level
	// classification; other preserved outcomes keep the worker's mode.
	res.FailureMode = classifyLandingFailureMode(landing.Outcome, landing.Reason, landing.GateResults, res.FailureMode)
	res.OrchestratorStatus = res.Status
}

// ExtractGoverningIDsFromManifest reads governing artifact IDs from a manifest
// JSON file at manifestAbs (absolute path). Returns nil when the file cannot
// be read. Callers use this to populate BeadLandingOptions.GovernIDs.
func ExtractGoverningIDsFromManifest(manifestAbs string) []string {
	if manifestAbs == "" {
		return nil
	}
	type manifestShape struct {
		Governing []struct {
			ID string `json:"id"`
		} `json:"governing"`
	}
	raw, err := os.ReadFile(manifestAbs)
	if err != nil {
		return nil
	}
	var m manifestShape
	if err := json.Unmarshal(raw, &m); err != nil {
		return nil
	}

	}
}

if runtime.TargetBeadID == "" {
	if reopened, reopenErr := autoReopenRetryableProviderConnectivityProposals(ctx, w.Store, assignee, now().UTC(), emit); reopenErr != nil {
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "provider-connectivity auto-reopen failed: %v; continuing\n", reopenErr)
		}
		emit("provider_connectivity.auto_reopen_error", map[string]any{
			"error": reopenErr.Error(),
		})
	} else if reopened > 0 && runtime.Log != nil {
		_, _ = fmt.Fprintf(runtime.Log, "provider-connectivity auto-reopened %d operator-attention bead(s)\n", reopened)
	}
}

candidate, skips, ok, err := w.nextCandidate(ctx, result.Results[resultsResetIdx:], []work.Guard{complexityGuard, preclaimGuard}, runtime.LabelFilter, runtime.TargetBeadID)
if err != nil {
	setExit("FatalConfig", "fatal_config")
	return result, err
}
// Diagnostic: when nextCandidate selected a lower-priority bead while
// at least one higher-priority bead was skipped, emit a structured
// picker.priority_skip event naming each skipped bead and the reason
// (ddx-9d55601f AC #4). Without this surface, an operator who sees a
// worker claim a P2 while P0s sit in `ddx bead ready` cannot tell
// whether the picker has a bug, the P0s are filtered upstream, or a
// label filter is in play.
if ok {
	emitPickerPrioritySkips(emit, candidate, skips)
}
if !ok {
	if detail, reasonCode, idleBeadID, isIdle := preClaimIdleSkip(skips); isIdle {
		if runtime.Log != nil && !wasIdle {
			_, _ = fmt.Fprintf(runtime.Log, "pre-claim hook blocked queue: %s; sleeping %s\n", detail, idleInterval)
		}
		emit("loop.idle", map[string]any{
			"reason":        reasonCode,
			"detail":        detail,
			"idle_interval": idleInterval.String(),
		})
		emitProgress(runtime.ProgressCh, ProgressEvent{
			EventID:   "evt-" + randomProgressID(),
			WorkerID:  runtime.WorkerID,
			ProjectID: runtime.ProjectRoot,
			Phase:     "loop.idle",
			Heartbeat: true,
			TS:        now().UTC(),
			Message:   reasonCode,
		})
		wasIdle = true

		// Same-detail escalation (ddx-df77e668 AC #3): count consecutive
		// idle cycles on an identical blocker and emit a non-terminal
		// operator-attention event once the streak crosses the threshold,
		// instead of looping silently forever.
		if detail == preClaimIdleDetail {
			preClaimIdleStreak++
		} else {
			preClaimIdleDetail = detail
			preClaimIdleStreak = 1
			preClaimIdleFirstAt = now().UTC()
			preClaimIdleEscalated = false
		}
		if preClaimIdleStreak >= preClaimIdleEscalationThreshold && !preClaimIdleEscalated {
			preClaimIdleEscalated = true
			elapsedIdle := now().UTC().Sub(preClaimIdleFirstAt)
			emit("loop.operator_attention", map[string]any{
				"reason":       "preclaim_idle_escalation",
				"bead_id":      idleBeadID,
				"detail":       detail,
				"elapsed_idle": elapsedIdle.String(),
				"idle_count":   preClaimIdleStreak,
			})
			if runtime.Log != nil {
